var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"헉…… 헉……","JPN":"はぁ……はぁ……","ENG":"*Huff* *Huff*","TWN":"呼……呼……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"제길……! 이 멍청한 것들!","JPN":"ちくしょう……！　このアホウども！","ENG":"Dammit...! Those idiots!","TWN":"該死……！沒用的東西！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"잘난 듯이 떠들어 놓고 이런 하찮은 함정에 빠진다고?","JPN":"偉そうな口をたたいておいて、こんなくだらない罠にかかるだと？","ENG":"Talking like they had everything under control, and they fall for the easiest trick in the book.","TWN":"在那邊一副多厲害的樣子，結果竟然掉到這種陷阱裡？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"펠릭스를 직접 만나야겠어. 유다 놈의 연구자료를 받아 내가 무녀를 완성시키는 거야.","JPN":"直接フェリックスに会わねば。ユダの研究資料を手に入れ、わしが巫女を完成させるのだ。","ENG":"I must go see Felix. I will take Judas' research and complete the priestess on my own.","TWN":"必須親自去找菲利克斯一趟，我要把尤達那傢伙的研究資料拿來，自己完成巫女！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그나마 마지막 협상수단은 남겨둬서 다행이군.","JPN":"それでも最後の交渉手段を残しておいたのは幸いじゃった。","ENG":"Fortunately, I still have leverage for one last negotiation.","TWN":"幸好我還有留一手。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"음……?","JPN":"うむ……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"이, 이게…… 어떻게 된 거지? 분명 이곳에 숨겨뒀을 텐데?","JPN":"こ、これは……どういうことだ？　確かにここに隠しておいたはずだが。","ENG":"W-where is it...? I am certain I hid it here...","TWN":"這，這……怎麼回事？我不是藏在這裡嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"다급해보이는군, 하바키.","JPN":"慌ててどうした、覇吐。","ENG":"What is the rush, Habaki?","TWN":"你看起來很慌張呢，幅木。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다……? 네놈이 왜 여기에……?","JPN":"ユダ……？　お前がなぜここにいる……？","ENG":"Judas? Why are you here...?","TWN":"尤達……？你怎麼在這裡……？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"날 미행한 건가?","JPN":"わしを尾行していたのか？","ENG":"Were you following me?","TWN":"你跟蹤我？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 찾고 있는 게 이 앰플인가?","JPN":"そなたが探しているのはこのアンプルか？","ENG":"This ample. Is this what you are looking for?","TWN":"你在找這個嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그…… 그걸 네가 어떻게 가지고 있는 거지?!","JPN":"そ……それをなぜお前が持っているのだ！？","ENG":"How… How do you have that?!","TWN":"那個……怎麼會在你那裡？！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……역신의 피.","JPN":"……疫病神の血。","ENG":"...The blood of the Plague God.","TWN":"……瘟神血液。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리가 그대와 계약했을 때부터 줄곧 요구해왔던 물건이지.","JPN":"我らがそなたと契約した時からずっと要求してきたものだな。","ENG":"It is what I have been asking for from the start of our partnership.","TWN":"這是打從我們和你簽約時就一直要求的東西吧。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"네놈! 그걸 어떻게 나보다 먼저 찾아낸 거냐?","JPN":"貴様！　それをどうやってわしよりも先に探し出せた？","ENG":"How dare you! You looked for that before even thinking of trying to find me?!","TWN":"你！你怎麼會比我先找到？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마…… 예견을 이용한 건가?","JPN":"まさか……予言を利用したのか？","ENG":"Or... did you use foresight?","TWN":"難道你……利用預知的能力？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇소. 우리가 관측할 수 있는 건 확정된 미래.","JPN":"そうだ。我らが観測できるのは確定された未来。","ENG":"Yes. What we can perceive is the set future.","TWN":"沒錯，我們可以觀測到的是確定的未來。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇기에 그대가 도망쳐서 이것을 챙겨야만 하는 상황을 만들었지.","JPN":"そのためにそなたが逃げ、これを持ち出さねばならない状況を作った。","ENG":"Thus, you were manipulated to run away and come looking for this.","TWN":"所以才營造出一個你逃跑後必須來取走它的情境。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그렇다는 건 처음부터…… 그게 놈들의 함정이란 걸 알고도 일부러 당했다는 거냐?","JPN":"なら最初から……これがやつらの罠であることを知っていながらわざわざやられたというのか？","ENG":"Then that can only mean... that you knew from the start that there was a trap?","TWN":"你的意思是……你從頭到尾都知道這是個陷阱，還故意掉進去嗎？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 이걸 우리에게 순순히 넘기지 않으리란 걸 알기에, 달리 방법이 없었소.","JPN":"そなたがこれを我らに素直に渡さないと知っていたので、他に方法がなかったのだ。","ENG":"We had no choice, for we knew you would not hand it over so easily.","TWN":"因為我知道你不會乖乖將它交給我們，只好出此下策。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"다행히, 역신의 피를 가지고 있다는 건 거짓말이 아니더군.","JPN":"疫病神の血を持っているというのが嘘でなくて幸いだ。","ENG":"Luckily, you were not lying when you claimed to possess the blood of the Plague God.","TWN":"幸好，你說你有瘟神血液這件事不是假的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"크윽! 네놈이 감히 날 배반해?","JPN":"くっ！　貴様、わしを裏切ったのか？","ENG":"Kgh! You dare betray me?!","TWN":"咳咳！你竟敢背叛我？！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"말에 어폐가 있군, 하바키.","JPN":"語弊があるな、覇吐。","ENG":"Habaki, you are mistaken.","TWN":"幅木，你這話有語病。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리는 그대의 배반을 사전에 차단했을 뿐이오.","JPN":"我らはそなたの裏切りを事前に防止したまでだ。","ENG":"We did not betray you, we prevented you from betraying us.","TWN":"我們只是搶先一步阻止你背叛我們而已。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"날 믿지 못하고 펠릭스 사령관과 손을 잡으려 하다니, 실망스럽군.","JPN":"私を信じられずフェリックス司令官と手を組もうとするなど、がっかりさせてくれる。","ENG":"How disappointing to learn that you were going to work with Commander Felix instead of putting your trust in me.","TWN":"你竟然不相信我，還想跟菲利克斯司令官合作，我感到很失望。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"웃기지 마라! 네가 그토록 자랑하던 딸은 내가 붙잡힐 때까지 코빼기도 내비치지 않았어!","JPN":"ふざけるな！　お前があんなに自慢していた娘はわしが捕まるまで顔も見せなかったではないか！","ENG":"Don't make me laugh! That daughter you keep boasting about never even showed up once while I was captured!","TWN":"真可笑！你那引以為傲的女兒在我被抓時根本都沒露面！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"처음부터 이럴 작정이었던 거냐!","JPN":"最初からこうするつもりだったのか！","ENG":"This was your plan all along, no?!","TWN":"你從一開始就打算這麼做吧！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"TWN":"  "},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L38_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이건 어디까지나 우리 공통의 목적을 이루기 위해서요.","JPN":"すべては我らの共通の目的を達成するためだ。","ENG":"All of this was to achieve a common goal.","TWN":"就某個層面而言，我也是為了要完成我們共同的目標。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대는 신의 힘을 이용하고 싶어했고, 나는 그 바람을 실현하고자 했을 뿐이지.","JPN":"そなたは神の力を利用することを望み、私はその願いを実現しようとした。","ENG":"You wanted the powers of god, and I wanted to make your wish achievable.","TWN":"你想利用神力，而我不過是替你實現心願而已。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"무녀가 가진 힘을 우리의 규칙으로 재현할 수 있다면……","JPN":"巫女が持つ力を我らの法則により再現できるのなら……","ENG":"If we are able to reproduce the powers of the priestess in our terms...","TWN":"若是可以照我們的方法重現巫女的能力……"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대들이 섬기는 신이라는 존재를 이론적으로 재현하는 것도 불가능은 아닐 것이오.","JPN":"そなたたちが崇める神という存在を理論的に再現することも不可能ではないだろう。","ENG":"Theoretically, it will not be long before creating the god you all so worship.","TWN":"那理論上，要重現你們侍奉的神也不是不可能的吧。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"신을…… 만들어낸다고? 역신의 피로?","JPN":"神を……作り出す？　疫病神の血で？","ENG":"Create... a god? With the blood of the Plague God?","TWN":"你……要造神？用瘟神血液？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"가능성은 충분하오. 나는 내 손을 통해 새로운 신이 탄생하는 미래를 이미 확인했으니까.","JPN":"可能性は十分にある。私は自分の手で新しい神が誕生する未来をすでに確認しているからな。","ENG":"Yes, it is more than possible. I have witnessed the birth of a new god, born with my own hands.","TWN":"這是有可能的，因為我已經確認未來會有新的神藉由我的手而生。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"멍청한 소리!","JPN":"バカなことを！","ENG":"Nonsense!","TWN":"說什麼蠢話！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"인간은 신의 신체에 담긴 사념을 견딜 수 없다! 감당하지 못해!","JPN":"人間は神の体に宿った邪念に耐えられない！　使いこなせぬ！","ENG":"A mortal cannot withstand the ideals contained within a god's body! They just cannot!","TWN":"人類是無法承受神體內的意志的！這是不可能的！"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"아니, 통제할 수 있소. 신을 받아들일 그릇만 있다면 말이지.","JPN":"いや、統制できる。神を受け入れる器さえあればな。","ENG":"True, but it can be controlled. If the vessel is worthy enough.","TWN":"不，是可以控制的，只要有可以承受神的器皿。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……나오님!","JPN":"……ナオ様！","ENG":"...Miss Nao!","TWN":"……奈緒大人！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나오님! 괜찮으신가요?","JPN":"ナオ様、大丈夫ですか？","ENG":"Miss Nao! Are you okay?","TWN":"奈緒大人！您還好嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……작은 당주?","JPN":"……チビ当主？","ENG":"...Ladychild?","TWN":"……小堂主？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다행입니다. 출혈이 너무 심해서 걱정했어요.","JPN":"よかった。出血が酷すぎて心配しておりました。","ENG":"Thank goodness. I was worried because your bleeding is severe.","TWN":"太好了，你流好多血，我很擔心。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"걱정 마라. 내 역신베기를 완성하기 전까진 죽을 생각 없으니까.","JPN":"案ずるな。わしは大蛇薙剣を完成するまで死ぬつもりはない。","ENG":"Don't worry. I have no intention of dying before completing Orochinagi.","TWN":"放心，在瘟神斬完成之前我是不會死的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그보다…… 그 가면 계집이 이곳에 와서 결계옥을 훔쳐갔다.","JPN":"それより……あの仮面娘がここへ来て結界玉を盗んでいったぞ。","ENG":"However... That masked girl came here and stole Akaitama.","TWN":"問題是……結界玉石現在落到那個面具丫頭的手裡。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"역시 결계가 사라진 건 하바키의 짓이군요.","JPN":"やはり結界が消えたのは覇吐の仕業だったのですね。","ENG":"So it was Habaki's doing...","TWN":"結界瓦解一事果然是幅木所為嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"틀렸어.","JPN":"違う。","ENG":"You're wrong.","TWN":"不是。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Pardon?","TWN":"不是嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"하바키 그 녀석은 아무것도 모를 거다. 속고 있는 거야.","JPN":"覇吐のやつは何もわかっておらん。騙されているのじゃ。","ENG":"Habaki knows nothing. He's been fooled.","TWN":"幅木那傢伙應該不知情，他是被蒙在鼓裡的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"놈이 가문연합의 사람이라면, 결계옥이 제 자릴 벗어나는 순간 현실이 뒤틀리고 만다는 걸 모를 리 없으니까.","JPN":"やつが連合の一員なら、結界玉がその位置から離れた瞬間に現実が歪んでしまうということを知らぬわけがない。","ENG":"Having been a member of the Family Alliance, he knows moving Akaitama from its place brings a distortion of reality.","TWN":"畢竟那傢伙是家族聯盟的人，他不可能不知道失去結界玉石的瞬間，現世就會瓦解。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 사나에는 어떻게 된 거죠? 그자가 데려간 건가요?","JPN":"だとしたら早苗はどうなったのですか？　あの者が連れて行ったのですか？","ENG":"Then, what happened to Sanae? Did they take her?","TWN":"不過早苗呢？她被抓走了嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"무슨 소리야? 녀석이라면 나랑 같이 그 가면 계집에게 당해서 이쯤에 널브러져……","JPN":"何を言っておる？　やつならわしと一緒にあの仮面娘にやられてここら辺に伸びて……","ENG":"Huh? No. She and I were defeated by that masked girl, so she should be lying on the ground somewhere her–","TWN":"你在說什麼？她和我一樣受到面具丫頭的攻擊，現在應該趴在地上……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……뭣? 어디 갔지?","JPN":"……なっ？　どこへ行った？","ENG":"Huh? Where did she go?","TWN":"……嗯？她人呢？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"신을 받아들일…… 그릇이라고?","JPN":"神を受け入れる……器だと？","ENG":"A vessel... worthy of a god?","TWN":"能夠承受神的……器皿？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그렇다오.","JPN":"そうだ。","ENG":"Correct.","TWN":"正確。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"나는 오랫동안 신성을 견뎌낼 수 있는 샘플을 찾아왔소.","JPN":"私は長い間神性に耐えられるサンプルを探してきた。","ENG":"I have been searching for a sample that can endure Divinity for a long time.","TWN":"我一直尋找能夠承受神性的樣本。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 선별과정에서 대부분은 견디지 못하고 죽거나, 괴물이 되었지.","JPN":"だが選別の過程でほとんどは耐えられずに死んだり、化け物になった。","ENG":"But in the process, most die or turn into monsters.","TWN":"只是在篩選的過程中，大部分都無法承受，結果不是死亡就是變成怪物。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그러던 중 하바키 그대를 만났고, 나나하라 무녀가 신성에 저항할 수 있다는 걸 발견했다오.","JPN":"そういった中で覇吐、そなたに出会い七原家の巫女が神性に抵抗できるということを発見した。","ENG":"That is when I met you, Habaki, and learned that Nanahara priestesses can resist Divinity.","TWN":"後來我遇到你才發現，原來七原巫女可以承受神性。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"그래서…… 무슨 소릴 하고 싶은 거지?","JPN":"それで……何が言いたい？","ENG":"So... What are you trying to say?","TWN":"然後呢……你到底想說什麼？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"생각해보시오, 하바키.","JPN":"考えてみろ、覇吐。","ENG":"Think, Habaki.","TWN":"幅木，你想想，"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"인간의 몸과 신의 영혼을 결합할 수 있다면, 우린 비로소 신의 껍데기 따위가 아닌 그 본질을 연구할 수 있게 되는 거요.","JPN":"人間の体と神の魂を結合させられれば、我々は神の殻などではなくその本質を研究することができるようになるのだ。","ENG":"If there was a way to fuse the soul of a god to a mortal vessel... Then we would be able to study not just the shell of a god, but its nature.","TWN":"要是人的身體和神的靈魂可以結合在一起，那我們就可以研究神的本質，而非只是神的外殼。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"인간의 몸에 신의 영혼을……? 그게 가당키나 한 소리인가?","JPN":"人間の身体に神の魂を……？　とんでもない話ではないか。","ENG":"A god's soul in a human body...? Do you even hear yourself?!","TWN":"人的身體和神的靈魂……？這合理嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"나 또한 무지한 채로 다른 이에게 그런 얘길 들었다면 믿지 않았겠지.","JPN":"私も無知なまま他の者からそんな話を聞いても信じなかっただろう。","ENG":"I too would react the same way if I were not enlightened.","TWN":"要是我在一無所知的情況聽到這種話，也會覺得難以置信。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"하지만 그대들의 역사엔, 이미 그 실험을 성공한 전례가 있더군.","JPN":"だがそなたたちの歴史には、すでにその実験に成功した前例があった。","ENG":"However, throughout your history, there have been successful cases of this experiment.","TWN":"但在你們的歷史中就有實驗成功的先例，"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"오로치가 삼킨 최초의 무녀 말이오.","JPN":"オロチが飲み込んだ最初の巫女のことだ。","ENG":"For instance, the first priestess Orochi swallowed.","TWN":"就是遭大蛇吞吃掉的初代巫女。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"흥, 그럴싸한 얘기다만 헛된 꿈이다. 애초에 지금은 존재하지도 않는 신의 영혼을 대체 무슨 수로 구한다는……","JPN":"ふん、それらしい話だがむなしい夢だな。そもそも今は存在もしていない神の魂をどうやって手に入れ……","ENG":"Hmph. Plausible, but a daft idea, I say. How are you supposed to find the soul of a god when it does not even exis–","TWN":"哼，雖然你說得頭頭是道，但這根本是天方夜譚。神的靈魂根本不存在，你要從哪弄到……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"설마……?!","JPN":"まさか……！？","ENG":"You cannot be thinking of...!","TWN":"該不會……？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대들이 소중히 여기는 결계옥은 신의 영혼으로 만들어진 것이지.","JPN":"そなたたちが大事にしている結界玉は神の魂で作られたものだな。","ENG":"Akaitama you all cherish. It was made with the soul of a god.","TWN":"你們視為珍寶的結界玉石就是用神的靈魂做的吧？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"지금쯤이면 레노어가 결계옥의 회수를 마쳤을 거요.","JPN":"今頃レノアが結界玉を回収しているはずだ。","ENG":"By now, Lenore should have it in her possession.","TWN":"結界玉石現在應該已經在蕾諾雅手中。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"……어리석군! 명부신은 흉신이 되지 않기 위해 스스로를 봉인한 것이다!","JPN":"……愚かな！　冥府の神は凶神とならないために自らを封印したのだぞ！","ENG":"...You fool! The Nether God purposefully sealed himself to not become a Fiend!","TWN":"……真是愚蠢！冥府神就是因為不想成為凶神，才把自己封印起來的！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"네놈이 말하는 계획이 성공한다 해도, 깨어나는 건 돌아갈 곳을 잃은 괴물일 뿐이지 멀쩡한 신이 아니야!","JPN":"貴様の言う計画が成功するとしても、目覚めるのは帰るところを失った化け物でまともな神ではない！","ENG":"Even if your plan succeeds, you will be waking up a monster with no purpose! Not a god!","TWN":"假設你的計畫成功，喚醒的也不是神，而是無處可歸的怪物！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"네놈들의 세상이 멸망해도 상관없다는 말이냐?!","JPN":"貴様らの世界が滅びてもいいというのか！？","ENG":"Are you that indifferent to if the world will end?!","TWN":"就算世界毀滅你們也無所謂嗎？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"내가 말했잖소.","JPN":"言ったはずだ。","ENG":"I have told you before.","TWN":"我應該有說過，"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리의 계획은 성공하든 실패하든 상관없다고.","JPN":"計画が成功しようがしまいが関係ないと。","ENG":"It does not matter whether our plan is successful or not.","TWN":"計畫成功與否都無所謂。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"유다……","JPN":"ユダ……","ENG":"Judas...","TWN":"尤達……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"네 이놈……!!!","JPN":"貴様……！！！","ENG":"You cannot be–!!","TWN":"你這傢伙……！！！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L1_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"……으윽?!","JPN":"……ううっ！？","ENG":"...Ngh?!","TWN":"……呃？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELDER_NPC_NANAHARA_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"커헉!!","JPN":"ガハッ！！","ENG":"Kuh!!","TWN":"咳咳！！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MOVEMENT_12"},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"우리의 계획을 앞당겨줘서 고맙소, 하바키.","JPN":"私たちの計画を早めてくれたことには感謝しよう、覇吐。","ENG":"Habaki. I thank you for speeding up our plan.","TWN":"幅木，謝謝你讓我們的計畫提前。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"개…… 같은 자식……!","JPN":"く……そ野郎……！","ENG":"You... Son of a...!","TWN":"混帳……東西……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"머리를 자를까요, 아버지?","JPN":"首を切りましょうか？　お父様。","ENG":"Father? Shall I cut off his head?","TWN":"父親，要把他的頭砍下來嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"아니다. 우리에게 도움을 준 오랜 친우를 그런 식으로 보내는 건 예우가 아니지.","JPN":"いや。我らを長らく手伝ってくれた古き友人をそんな風に逝かせるのは失礼だろう。","ENG":"No. We should not be disrespectful to our old friends.","TWN":"不，怎麼可以這樣對待我們的合作夥伴，這樣有失禮貌。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그러니 기회를 한 번 주겠소, 하바키.","JPN":"だからもう一回機会を与えてやろう、覇吐。","ENG":"So, I will give you another chance, Habaki.","TWN":"我再給你一次機會，幅木。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 이 역신의 피를 견뎌낸다면, 그대는 살 것이오.","JPN":"この疫病神の血に耐えられれば、そなたは生き延びられるだろう。","ENG":"If you endure the blood of the Plague God, you will live.","TWN":"只要你能夠承受瘟神血液，就能活命。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELDER_NPC_NANAHARA_NAME","text":{"KOREA":"아…… 안돼. 그만 둬……!","JPN":"だ……ダメだ。やめろ……！","ENG":"N-no...! S-stop...!","TWN":"不……不要，住手……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그럼, 뒤를 부탁하겠소.","JPN":"それでは、後を頼むぞ。","ENG":"Then, I leave the rest to you.","TWN":"接下來就看你自己的造化囉。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"크아아아아악!!!","JPN":"クアアアアアッ！！！","ENG":"Graaah!","TWN":"呃啊啊啊阿！！！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_PAWN_DAMAGE_DOWN"}]`);export{e as default};